from collections import defaultdict

def train_bpe(corpus: list[str], num_merges: int) -> tuple[list[tuple], dict]:
    # Initialize: each word as tuple of chars + </w>, with frequency 1
    vocab = defaultdict(int)
    for word in corpus:
        symbols = tuple(list(word) + ['</w>'])
        vocab[symbols] += 1

    def get_pairs(vocab):
        pairs = defaultdict(int)
        for symbols, freq in vocab.items():
            for i in range(len(symbols) - 1):
                pairs[(symbols[i], symbols[i+1])] += freq
        return pairs

    def merge_vocab(pair, vocab):
        new_vocab = defaultdict(int)
        bigram = ' '.join(pair)
        replacement = ''.join(pair)
        for symbols, freq in vocab.items():
            # Replace occurrences of pair
            s = ' '.join(symbols)
            s = s.replace(bigram, replacement)
            new_vocab[tuple(s.split())] += freq
        return new_vocab

    merges = []
    for _ in range(num_merges):
        pairs = get_pairs(vocab)
        if not pairs:
            break
        # Best pair: highest freq, break ties lexicographically
        best = max(pairs, key=lambda p: (pairs[p], p))
        merges.append(best)
        vocab = merge_vocab(best, vocab)

    return merges, dict(vocab)
